const b = $json.body || $json;
const clean = (v) => (v ?? '').toString().trim();
const clientId = Number(clean(b.client_id));
const caseId = clean(b.case_id) ? Number(clean(b.case_id)) : null;
const amount = Number(clean(b.amount));
const dueDate = clean(b.due_date);
const currency = clean(b.currency) || 'DOP';
const valid = Number.isFinite(clientId) && Number.isFinite(amount) && amount > 0;
return [{json:{
  valid,
  error: valid ? '' : 'Campos requeridos: client_id y amount>0',
  client_id: clientId,
  case_id: Number.isFinite(caseId) ? caseId : null,
  amount,
  due_date: dueDate || null,
  currency
}}];

return $input.all().map(i => ({ json: {
  case_id: i.json.case_id || null,
  payload: { invoice_id: i.json.id, amount: i.json.amount, currency: i.json.currency, due_date: i.json.due_date },
  event_type: 'invoice_overdue'
}}));
